select.if:
WITH RECURSIVE category_tree AS ( SELECT id FROM gb_categories WHERE id = #{categoryId} AND del_flag = '0' UNION ALL SELECT c.id FROM gb_categories c INNER JOIN category_tree ct ON c.parent_id = ct.id WHERE c.del_flag = '0' )
select b.id, b.site_id, b.name, b.description, b.logo_url, b.banner_url, b.qrcode_url, b.official_url, b.download_url, b.android_url, b.ios_url, b.promote_url_1, b.promote_url_2, b.promote_url_3, b.register_download_url, b.discount_rate, b.features, b.sort_order, b.del_flag, b.create_by, b.create_time, b.update_by, b.update_time, b.remark, b.category_id, IFNULL(game_cnt.cnt, 0) as game_count, IFNULL(site_rel_cnt.incl_cnt, 0) as related_sites_count, IFNULL(site_rel_cnt.excl_cnt, 0) as excluded_sites_count, c.name as category_name, c.icon as category_icon, -- 统一的可见性状态： -- 1. 自有盒子（site_id = 当前网站）：使用盒子本身的status -- 2. 用户默认站点（site_id = personalSiteId）： -- - 如果有关联记录（incl.id不为空），使用关联表的is_visible（忽略排除逻辑） -- - 如果没有关联记录，使用排除逻辑（有excl记录则不可见，否则可见） -- 3. 其他网站盒子：使用关联表的is_visible（必须有关联记录才能访问） CASE WHEN b.site_id = #{siteId} THEN b.status WHEN b.site_id = #{params.personalSiteId} THEN (CASE WHEN incl.id IS NOT NULL THEN incl.is_visible WHEN excl.id IS NULL THEN '1' ELSE '0' END) ELSE IFNULL(incl.is_visible, '0') END as is_visible, -- 关联来源标识 CASE WHEN b.site_id = #{siteId} THEN 'own' WHEN b.site_id = #{params.personalSiteId} THEN 'default' ELSE 'shared' END as relation_source, -- 是否被排除（仅对默认配置且无关联记录时有效） CASE WHEN b.site_id = #{params.personalSiteId} AND incl.id IS NULL AND excl.id IS NOT NULL THEN '1' ELSE '0' END as is_excluded from gb_game_boxes b left join gb_categories c on b.category_id = c.id and c.del_flag = '0' -- 左连接正向关联（include） LEFT JOIN gb_site_box_relations incl ON b.id = incl.box_id AND incl.site_id = #{siteId} AND incl.relation_type = 'include' -- 左连接排除关联（exclude） LEFT JOIN gb_site_box_relations excl ON b.id = excl.box_id AND excl.site_id = #{siteId} AND excl.relation_type = 'exclude' -- 预聚合：当前站点可见游戏数（三源：own+default+shared），避免 N+1 关联子查询 LEFT JOIN ( SELECT r2.box_id, COUNT(*) AS cnt FROM gb_box_game_relations r2 INNER JOIN gb_games g2 ON r2.game_id = g2.id AND g2.del_flag = '0' LEFT JOIN gb_site_game_relations gincl2 ON g2.id = gincl2.game_id AND gincl2.site_id = #{siteId} AND gincl2.relation_type = 'include' LEFT JOIN gb_site_game_relations gexcl2 ON g2.id = gexcl2.game_id AND gexcl2.site_id = #{siteId} AND gexcl2.relation_type = 'exclude' WHERE ( (g2.site_id = #{siteId} AND g2.status = '1') OR (g2.site_id = #{params.personalSiteId} AND ( CASE WHEN g2.status = '0' THEN '0' WHEN gincl2.id IS NOT NULL THEN gincl2.is_visible WHEN gexcl2.id IS NULL THEN '1' ELSE '0' END) = '1') OR (g2.site_id != #{siteId} AND g2.site_id != #{params.personalSiteId} AND gincl2.id IS NOT NULL AND IFNULL(gincl2.is_visible, '0') = '1') ) GROUP BY r2.box_id ) game_cnt ON b.id = game_cnt.box_id -- 预聚合：关联/排除站点数量 LEFT JOIN ( SELECT box_id, SUM(CASE WHEN relation_type = 'include' THEN 1 ELSE 0 END) AS incl_cnt, SUM(CASE WHEN relation_type = 'exclude' THEN 1 ELSE 0 END) AS excl_cnt FROM gb_site_box_relations GROUP BY box_id ) site_rel_cnt ON b.id = site_rel_cnt.box_id
b.del_flag = '0'
AND ( b.site_id = #{siteId}
OR b.site_id = #{params.personalSiteId}
OR (b.site_id != #{siteId}
AND b.site_id != #{params.personalSiteId}
AND incl.id IS NOT NULL) ) and b.name like concat('%', #{name}, '%')
and ( b.category_id IN (SELECT id FROM category_tree) OR b.id IN ( SELECT DISTINCT bcr.box_id FROM gb_box_category_relations bcr WHERE bcr.category_id IN (SELECT id FROM category_tree) ) )
and b.status = #{status}
order by b.sort_order asc, b.create_time desc

mapper.update:
update gb_game_boxes
site_id = #{siteId}, name = #{name}, description = #{description}, category_id = #{categoryId}, logo_url = #{logoUrl}, banner_url = #{bannerUrl}, qrcode_url = #{qrcodeUrl}, official_url = #{officialUrl}, download_url = #{downloadUrl}, android_url = #{androidUrl}, ios_url = #{iosUrl}, promote_url_1 = #{promoteUrl1}, promote_url_2 = #{promoteUrl2}, promote_url_3 = #{promoteUrl3}, register_download_url = #{registerDownloadUrl}, discount_rate = #{discountRate}, features = #{features}, game_count = #{gameCount}, sort_order = #{sortOrder}, priority = #{priority}, status = #{status}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where id = #{id}
